#include <bits/stdc++.h>

using namespace std;

long long maxSumKElements(vector<long long>& arr, int k) {
    int n = arr.size();

    // Calculate the sum of the first k elements
    long long current_sum = 0;
    for (int i = 0; i < k; ++i) {
        current_sum += arr[i];
    }

    // This is the initial maximum sum (taking all k elements from the start)
    long long max_sum = current_sum;

    // Two-pointer technique: start from the end of the array and replace elements from the start
    for (int i = 0; i < k; ++i) {
        current_sum = current_sum - arr[k - 1 - i] + arr[n - 1 - i];
        max_sum = max(max_sum, current_sum);
    }

    return max_sum;
}

int main() {
    int n, k;

    // Taking user input for size of the array
    cin >> n;

    // Taking user input for the value of k
    cin >> k;

    vector<long long> arr(n);

    // Taking user input for the array elements
    for (int i = 0; i < n; ++i) {
        cin >> arr[i];
    }

    // Calling the function and printing the result
    cout << maxSumKElements(arr, k) << endl;

    return 0;
}

