import java.util.Scanner;

public class Main {
    public static long maxSumKElements(long[] arr, int k) {
        int n = arr.length;

        // Calculate the sum of the first k elements
        long currentSum = 0;
        for (int i = 0; i < k; ++i) {
            currentSum += arr[i];
        }

        // This is the initial maximum sum (taking all k elements from the start)
        long maxSum = currentSum;

        // Two-pointer technique: start from the end of the array and replace elements from the start
        for (int i = 0; i < k; ++i) {
            currentSum = currentSum - arr[k - 1 - i] + arr[n - 1 - i];
            maxSum = Math.max(maxSum, currentSum);
        }

        return maxSum;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int k = scanner.nextInt();
        long[] arr = new long[n];
        for (int i = 0; i < n; ++i) {
            arr[i] = scanner.nextLong();
        }

        System.out.println(maxSumKElements(arr, k));
    }
}
